div.script:
//
                try {
                var dbg = document.getElementById('debug_text');
                if (dbg) { dbg.textContent = 'JS: En cours...'; dbg.setAttribute('fill', '#f59e0b'); }
                var H = 'http://www.w3.org/1999/xhtml';
                function E(t) { return document.createElementNS(H, t); }
                function getEl(id) { return document.getElementById(id); }
                function showError(msg) { var e=getEl('error_box'); if(e){e.style.display='block'; e.innerHTML='Erreur: '+msg;} }
                function showToast(msg) { var t=getEl('toast'); if(t){t.textContent=msg; t.classList.add('show'); setTimeout(function(){t.classList.remove('show');},3000);} }
                function escapeXML(str) { if(!str) return ''; return str.toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&apos;'); }

                var DB_NAME = 'KizunaPro_v260_payslip_redesign';
                var defaultRules = [
                { code: "MAL", nom: "Sécurité Sociale (Maladie)", base: "brut", sal: 0.75, pat: 13.00, plafond: 0 },
                { code: "VIEP", nom: "Assurance Vieillesse Plafonnée", base: "brut", sal: 6.20, pat: 8.55, plafond: 1 },
                { code: "VIED", nom: "Assurance Vieillesse Déplafonnée", base: "brut", sal: 0.40, pat: 1.90, plafond: 0 },
                { code: "RETC", nom: "Retraite Complémentaire (TA)", base: "brut", sal: 3.15, pat: 4.72, plafond: 1 },
                { code: "CHOM", nom: "Assurance Chômage", base: "brut", sal: 0.00, pat: 4.05, plafond: 4 },
                { code: "CSGD", nom: "CSG/CRDS Déductible", base: "brut_abattu", sal: 6.80, pat: 0.00, plafond: 0 },
                { code: "CSGND", nom: "CSG/CRDS Non Déductible", base: "brut_abattu", sal: 2.40, pat: 0.00, plafond: 0 }
                ];
                var defaultDB = {
                company: { name: "Mon Entreprise SAS", address: "12 rue de l'Industrie, 75001 Paris", siret: "123 456 789 00012", ape: "6201Z", conv: "SYNTEC", logo: "" },
                employes: [
                { id: 1, nom: "Dubois", prenom: "Alice", sexe: "F", adresse: "10 rue Victor Hugo, 75011 Paris", num_ss: "285047512345", date_embauche: "2022-01-15", contrat: "CDI", poste: "Directrice Générale", salaire_base: 6000, temps_travail: 35, convention: "SYNTEC", rib: "FR76...", pas_rate: 10.0, rqth: false, rule_profile_id: 1 },
                { id: 2, nom: "Moreau", prenom: "Luc", sexe: "M", adresse: "5 Place Bellecour, 69000 Lyon", num_ss: "180106212345", date_embauche: "2023-09-01", contrat: "CDI", poste: "Commercial", salaire_base: 2200, temps_travail: 35, convention: "Commerce", rib: "FR76...", pas_rate: 2.5, rqth: false, rule_profile_id: 1 },
                { id: 3, nom: "Martin", prenom: "Paul", sexe: "M", adresse: "8 Av des Fleurs, 33000 Bordeaux", num_ss: "170057512345", date_embauche: "2023-03-10", contrat: "CDI", poste: "Agent d'entretien", salaire_base: 1500, temps_travail: 35, convention: "Bâtiment", rib: "FR76...", pas_rate: 0.0, rqth: true, rule_profile_id: 1 }
                ],
                bulletins: [],
                params: {
                taux_fillon: 0.3194, aide_rqth: 150,
                layout: { template: 'classique', font: 'Arial', size: '12px', margin: 30, cols: 2, titlecolor: '#f59e0b', titlebg: '#1a202c', header_note: '', note: "Virement effectué le 25 du mois." },
                rule_profiles: [
                { id: 1, name: "Standard 2024", smic: 1766.92, plafond_ss: 3864, rules: defaultRules }
                ],
                nextProfileId: 2
                },
                nextEmpId: 4, nextBullId: 1
                };

                var DB;
                try {
                var data = localStorage.getItem(DB_NAME);
                if (data) {
                DB = JSON.parse(data);
                if (!DB.company) DB.company = defaultDB.company;
                if (!DB.params) DB.params = defaultDB.params;
                if (!DB.params.rule_profiles) {
                var oldRules = DB.params.custom_rules || defaultRules;
                DB.params.rule_profiles = [{ id: 1, name: "Standard 2024", smic: DB.params.smic || 1766.92, plafond_ss: DB.params.plafond_ss || 3864, rules: oldRules }];
                DB.params.nextProfileId = 2;
                }
                if (!DB.params.layout) DB.params.layout = defaultDB.params.layout;
                if (!DB.employes || DB.employes.length === 0) DB.employes = defaultDB.employes;
                for (var i=0; i<DB.employes.length; i++) {
                    if (!DB.employes[i].rule_profile_id) DB.employes[i].rule_profile_id = 1;
                    }
                    } else { DB = JSON.parse(JSON.stringify(defaultDB)); }
                    } catch(e) { DB = JSON.parse(JSON.stringify(defaultDB)); }

                    function saveDB() { try { localStorage.setItem(DB_NAME, JSON.stringify(DB)); } catch(e) {} }

                    var currentRuleProfileId = 1;

                    function showView(viewName) {
                    var views = ['dashboard', 'employes', 'paie', 'historique', 'parametres'];
                    for (var i = 0; i < views.length; i++) { var el = getEl('view_' + views[i]); if (el) el.style.display = 'none'; }
                        var activeView = getEl('view_' + viewName);
                        if (activeView) activeView.style.display = 'block';
                        var btns = [{id:'btn_nav_dash', v:'dashboard'}, {id:'btn_nav_emp', v:'employes'}, {id:'btn_nav_pay', v:'paie'}, {id:'btn_nav_hist', v:'historique'}, {id:'btn_nav_param', v:'parametres'}];
                        for (var j = 0; j < btns.length; j++) { var b = getEl(btns[j].id); if (b) b.style.color = (btns[j].v === viewName) ? '#f59e0b' : '#a0aec0'; }
                            var sankey = getEl('sankey_group'); var hint = getEl('sankey_hint');
                            if (viewName === 'paie') { if(sankey) sankey.style.display = 'block'; if(hint) hint.style.display = 'block'; populatePayrollDropdown(); updateSlidersFromDB(); updateSankey(); }
                            else { if(sankey) sankey.style.display = 'none'; if(hint) hint.style.display = 'none'; }
                            if (viewName === 'historique') renderHistory();
                            if (viewName === 'parametres') loadParams();
                            if (viewName === 'dashboard') renderDashboard();
                            }

                            function updateSidebarStats() {
                            var globalYear = parseInt(getEl('global_year').value) || new Date().getFullYear();
                            getEl('side_emp_count').textContent = DB.employes.length;
                            var yearCost = 0;
                            for (var i=0; i<DB.bulletins.length; i++) { var b = DB.bulletins[i]; if (parseInt(b.annee) === globalYear) { yearCost += b.cout; } }
                                getEl('side_year_cost').textContent = Math.round(yearCost).toLocaleString('fr-FR') + ' €';
                                }

                                function renderEmployes() {
                                var tbody = getEl('emp_table_body'); if (!tbody) return; tbody.innerHTML = '';
                                for (var i = 0; i < DB.employes.length; i++) {
                                    var emp = DB.employes[i]; var tr = E('tr');
                                    tr.innerHTML = '<td>'+emp.id+'</td><td>'+emp.nom+' '+emp.prenom+'</td><td>'+emp.poste+'</td><td><span class="badge badge-'+emp.contrat.toLowerCase()+'">'+emp.contrat+'</span>'+(emp.rqth?'<span class="badge badge-rqth">RQTH</span>':'')+'<span class="badge '+(emp.sexe==='F'?'badge-f':'badge-h')+'">'+(emp.sexe==='F'?'Femme':'Homme')+'</span></td><td>'+emp.salaire_base+' €</td><td style="white-space:nowrap;"><button class="btn btn-sm" id="edit_emp_'+emp.id+'" style="margin-right:5px;">Éditer</button><button class="btn btn-sm btn-info" id="dup_emp_'+emp.id+'" style="margin-right:5px;">Dupliquer</button><button class="btn btn-sm btn-danger" id="del_emp_'+emp.id+'">Suppr.</button></td>';
                                    tbody.appendChild(tr);
                                    }
                                    updateSidebarStats();
                                    }

                                    function openEmpModal(id) {
                                    var modal = getEl('modal_emp'); if (!modal) return; modal.style.display = 'flex';
                                    var profileSelect = getEl('form_emp_profile'); profileSelect.innerHTML = '';
                                    for(var i=0; i<DB.params.rule_profiles.length; i++) {
                                        var p = DB.params.rule_profiles[i];
                                        var opt = E('option'); opt.value = p.id; opt.textContent = p.name; profileSelect.appendChild(opt);
                                        }

                                        if (id) {
                                        getEl('modal_emp_title').textContent = "Modifier le Salarié";
                                        var emp = DB.employes.find(function(e) { return e.id === id; });
                                        if (emp) {
                                        getEl('form_emp_id').value = emp.id; getEl('form_emp_nom').value = emp.nom; getEl('form_emp_prenom').value = emp.prenom;
                                        getEl('form_emp_poste').value = emp.poste; getEl('form_emp_date').value = emp.date_embauche; getEl('form_emp_contrat').value = emp.contrat;
                                        getEl('form_emp_salaire').value = emp.salaire_base; getEl('form_emp_pas').value = emp.pas_rate || 0.0;
                                        getEl('form_emp_conv').value = emp.convention; getEl('form_emp_adresse').value = emp.adresse; getEl('form_emp_ss').value = emp.num_ss; getEl('form_emp_iban').value = emp.rib;
                                        getEl('form_emp_rqth').value = emp.rqth ? "true" : "false"; getEl('form_emp_sexe').value = emp.sexe || "M";
                                        getEl('form_emp_profile').value = emp.rule_profile_id || 1;
                                        }
                                        } else {
                                        getEl('modal_emp_title').textContent = "Ajouter un Salarié"; getEl('form_emp_id').value = '';
                                        getEl('form_emp_date').value = new Date().toISOString().split('T')[0]; getEl('form_emp_contrat').value = 'CDI';
                                        getEl('form_emp_salaire').value = DB.params.rule_profiles[0].smic || 1766.92; getEl('form_emp_pas').value = 0.0; getEl('form_emp_conv').value = 'SYNTEC';
                                        getEl('form_emp_rqth').value = "false"; getEl('form_emp_sexe').value = "M"; getEl('form_emp_profile').value = 1;
                                        }
                                        }

                                        function populatePayrollDropdown() {
                                        var select = getEl('pay_select_emp'); if (!select) return; select.innerHTML = '';
                                        for (var i = 0; i < DB.employes.length; i++) {
                                            var emp = DB.employes[i]; var opt = E('option'); opt.value = emp.id; opt.textContent = emp.nom + ' ' + emp.prenom + ' (' + emp.poste + ')'; select.appendChild(opt);
                                            }
                                            }

                                            function populateBaseSelects() {
                                            var profile = DB.params.rule_profiles.find(function(p){ return p.id == currentRuleProfileId; }) || DB.params.rule_profiles[0];
                                            if(!profile) return;
                                            var rules = profile.rules;
                                            var ruleRows = document.querySelectorAll('#ctrl_box .rule-row');

                                            for(var i=0; i<ruleRows.length; i++) {
                                                var sel = getEl('rule_base_'+i); if(!sel) continue;
                                                var currentVal = sel.value;
                                                sel.innerHTML = '<option value="brut" '+(currentVal==='brut'?'selected="selected"':'')+'>Brut</option><option value="brut_abattu" '+(currentVal==='brut_abattu'?'selected="selected"':'')+'>Brut Abattu</option>';

                                                for(var j=0; j<rules.length; j++) {
                                                    if(j !== i) {
                                                    var code = rules[j].code || ('R'+j);
                                                    sel.innerHTML += '<option value="'+code+'" '+(currentVal===code?'selected="selected"':'')+'>'+code+'</option>';
                                                    }
                                                    }
                                                    }
                                                    }

                                                    function loadParams() {
                                                    getEl('company_name').value = DB.company.name; getEl('company_address').value = DB.company.address; getEl('company_siret').value = DB.company.siret; getEl('company_ape').value = DB.company.ape; getEl('company_conv').value = DB.company.conv; getEl('company_logo').value = DB.company.logo;
                                                    getEl('param_taux_fillon').value = DB.params.taux_fillon; getEl('param_aide_rqth').value = DB.params.aide_rqth;
                                                    getEl('param_layout_template').value = DB.params.layout.template || 'classique'; getEl('param_layout_font').value = DB.params.layout.font; getEl('param_layout_size').value = DB.params.layout.size; getEl('param_layout_margin').value = DB.params.layout.margin; getEl('param_layout_cols').value = DB.params.layout.cols || 2;
                                                    getEl('param_layout_titlecolor').value = DB.params.layout.titlecolor || '#f59e0b'; getEl('param_layout_titlebg').value = DB.params.layout.titlebg || '#1a202c'; getEl('param_layout_header_note').value = DB.params.layout.header_note || ''; getEl('param_layout_note').value = DB.params.layout.note || '';

                                                    var profSelect = getEl('rule_profile_select'); profSelect.innerHTML = '';
                                                    for(var i=0; i<DB.params.rule_profiles.length; i++) {
                                                        var p = DB.params.rule_profiles[i];
                                                        var opt = E('option'); opt.value = p.id; opt.textContent = p.name; profSelect.appendChild(opt);
                                                        }
                                                        profSelect.value = currentRuleProfileId;

                                                        var profile = DB.params.rule_profiles.find(function(p){ return p.id == currentRuleProfileId; }) || DB.params.rule_profiles[0];
                                                        if(!profile) return;

                                                        getEl('param_smic').value = profile.smic || 1766.92;
                                                        getEl('param_plafond').value = profile.plafond_ss || 3864;

                                                        var rules = profile.rules;

                                                        var ctrl = getEl('ctrl_box'); ctrl.innerHTML = '';
                                                        for (var i = 0; i < rules.length; i++) {
                                                            var r = rules[i];
                                                            var row = E('div'); row.setAttribute('class', 'rule-row'); row.style.display = 'grid'; row.style.gridTemplateColumns = '0.5fr 2fr 1fr 0.8fr 0.8fr 0.8fr 0.5fr'; row.style.gap = '5px';
                                                            row.innerHTML =
                                                            '<input type="text" value="' + escapeXML(r.code||"") + '" id="rule_code_'+i+'" style="text-transform:uppercase;" />' +
                                                            '<input type="text" value="' + escapeXML(r.nom) + '" id="rule_nom_'+i+'" />' +
                                                            '<select id="rule_base_'+i+'"><option value="brut" '+(r.base==='brut'?'selected="selected"':'')+'>Brut</option><option value="brut_abattu" '+(r.base==='brut_abattu'?'selected="selected"':'')+'>Brut Abattu</option></select>' +
                                                            '<input type="number" step="0.01" value="' + r.sal + '" id="rule_sal_'+i+'" style="text-align:right;" />' +
                                                            '<input type="number" step="0.01" value="' + r.pat + '" id="rule_pat_'+i+'" style="text-align:right;" />' +
                                                            '<select id="rule_plafond_'+i+'"><option value="0" '+(r.plafond===0?'selected="selected"':'')+'>Aucun</option><option value="1" '+(r.plafond===1?'selected="selected"':'')+'>1x PMSS</option><option value="4" '+(r.plafond===4?'selected="selected"':'')+'>4x PMSS</option><option value="8" '+(r.plafond===8?'selected="selected"':'')+'>8x PMSS</option></select>' +
                                                            '<button class="btn btn-danger btn-sm" id="del_rule_'+i+'">X</button>';
                                                            ctrl.appendChild(row);

                                                            var codeInput = getEl('rule_code_'+i);
                                                            if(codeInput) codeInput.addEventListener('change', populateBaseSelects);
                                                            }
                                                            populateBaseSelects();
                                                            }

                                                            var payRows = [];
                                                            function clearPayRows() { var c = getEl('dyn_rows_container'); if(c) c.innerHTML = ''; payRows = []; }
                                                            function addPayRow(label, base, formula, type) {
                                                            var c = getEl('dyn_rows_container'); if (!c) return; var r = E('div'); r.setAttribute('class', 'dyn-row');
                                                            r.innerHTML = '<input type="text" value="'+label+'" style="flex:2;" placeholder="Libellé" /><input type="number" value="'+base+'" style="flex:1;" placeholder="Base" /><input type="text" value="'+formula+'" style="flex:1.5;" placeholder="Formule" /><select style="flex:1"><option value="add_brut">+ Brut</option><option value="ded_brut">- Brut</option><option value="add_net">+ Net</option><option value="ded_net">- Net</option></select><button class="btn btn-danger btn-sm" style="width:30px;">X</button>';
                                                            r.querySelector('select').value = type || 'add_brut'; c.appendChild(r);
                                                            payRows.push({ rowDiv: r, labelInput: r.querySelectorAll('input')[0], baseInput: r.querySelectorAll('input')[1], formulaInput: r.querySelectorAll('input')[2], typeSelect: r.querySelector('select') });
                                                            var inps = r.querySelectorAll('input'); for(var i=0; i<inps.length; i++) inps[i].addEventListener('input', updateSankey);
                                                                r.querySelector('select').addEventListener('change', updateSankey);
                                                                r.querySelector('button').addEventListener('click', function() { c.removeChild(r); payRows = payRows.filter(function(p){ return p.rowDiv !== r; }); updateSankey(); });
                                                                }

                                                                function getActiveProfile(emp) {
                                                                var profileId = emp.rule_profile_id || 1;
                                                                return DB.params.rule_profiles.find(function(p){ return p.id == profileId; }) || DB.params.rule_profiles[0];
                                                                }

                                                                function calcPayroll() {
                                                                var empId = parseInt(getEl('pay_select_emp').value); var emp = DB.employes.find(function(e) { return e.id === empId; });
                                                                if (!emp) return { emp_cost:0, brut:0, pat:0, sal:0, net_social:0, net_imp:0, tax:0, net_pay:0, max_val:0, cotis_details:[], line_items:[], reduc_fillon:0, reduc_rqth:0 };

                                                                var profile = getActiveProfile(emp);
                                                                if(!profile) return { emp_cost:0, brut:0, pat:0, sal:0, net_social:0, net_imp:0, tax:0, net_pay:0, max_val:0, cotis_details:[], line_items:[], reduc_fillon:0, reduc_rqth:0 };

                                                                var brut = emp.salaire_base; var net_adjustments = 0; var lineItems = [];
                                                                for (var i = 0; i < payRows.length; i++) {
                                                                    var row = payRows[i]; var base = parseFloat(row.baseInput.value) || 0; var formula = row.formulaInput.value.trim() === '' ? 'base' : row.formulaInput.value;
                                                                    var f = formula.toString().toLowerCase().replace(/\s/g, '').replace(/base/gi, base); var amount = base;
                                                                    if (f !== '' && !isNaN(parseFloat(f)) && isFinite(f)) { amount = parseFloat(f); }
                                                                    var type = row.typeSelect.value; lineItems.push({ label: row.labelInput.value, amount: amount, type: type });
                                                                    if (type === 'add_brut') brut += amount; else if (type === 'ded_brut') brut -= amount; else if (type === 'add_net') net_adjustments += amount; else if (type === 'ded_net') net_adjustments -= amount;
                                                                    }

                                                                    var pmss = profile.plafond_ss || 3864;
                                                                    var smic = profile.smic || 1766.92;

                                                                    brut = Math.max(0, brut); var brut_abattu = brut * 0.9825;
                                                                    var sal_total = 0; var pat_total = 0; var cotisDetails = [];
                                                                    var computedAmounts = {};

                                                                    var rules = profile.rules;
                                                                    for (var i = 0; i < rules.length; i++) {
                                                                        var r = rules[i];
                                                                        var baseVal = 0;
                                                                        if (r.base === 'brut') baseVal = brut;
                                                                        else if (r.base === 'brut_abattu') baseVal = brut_abattu;
                                                                        else if (r.base === 'net') baseVal = net_social;
                                                                        else baseVal = computedAmounts[r.base] || 0;

                                                                        var cappedBase = baseVal;
                                                                        if (r.plafond > 0) { cappedBase = Math.min(baseVal, pmss * r.plafond); }

                                                                        var partSal = cappedBase * (r.sal / 100); var partPat = cappedBase * (r.pat / 100);
                                                                        sal_total += partSal; pat_total += partPat; cotisDetails.push({ nom: r.nom, sal: r.sal, pat: r.pat, partSal: partSal, partPat: partPat });

                                                                        var code = r.code || ("R"+i);
                                                                        computedAmounts[code] = (computedAmounts[code] || 0) + partSal + partPat;
                                                                        }
                                                                        var reduc_fillon = 0; if (brut > 0 && brut <= 1.6 * smic) { var coef = (DB.params.taux_fillon / 0.6) * ((1.6 * smic / brut) - 1); if (coef < 0) coef = 0; reduc_fillon = coef * brut; pat_total -= reduc_fillon; cotisDetails.push({ nom: "Réduction Fillon", sal: 0, pat: 0, partSal: 0, partPat: -reduc_fillon }); }
                                                                                var reduc_rqth = 0; if (emp.rqth) { reduc_rqth = DB.params.aide_rqth || 0; pat_total -= reduc_rqth; cotisDetails.push({ nom: "Aide RQTH", sal: 0, pat: 0, partSal: 0, partPat: -reduc_rqth }); }
                                                                                var net_social = brut - sal_total; var net_imp = net_social; var tax = net_imp * ((emp.pas_rate||0) / 100); var net_pay = net_imp - tax + net_adjustments; var emp_cost = brut + pat_total;
                                                                                return { emp_cost: emp_cost, brut: brut, pat: pat_total, sal: sal_total, net_social: net_social, net_imp: net_imp, tax: tax, net_pay: net_pay, max_val: emp_cost, pas_rate: emp.pas_rate||0, reduc_fillon: reduc_fillon, reduc_rqth: reduc_rqth, cotis_details: cotisDetails, line_items: lineItems };
                                                                                }

                                                                                function getSankeyPath(x1, y1_top, y1_bot, x2, y2_top, y2_bot) {
                                                                                var cx1 = x1 + (x2 - x1) * 0.5, cx2 = x2 - (x2 - x1) * 0.5;
                                                                                y1_top = Math.max(0, y1_top); y1_bot = Math.max(y1_top, y1_bot); y2_top = Math.max(0, y2_top); y2_bot = Math.max(y2_top, y2_bot);
                                                                                return "M "+x1+","+y1_top+" C "+cx1+","+y1_top+" "+cx2+","+y2_top+" "+x2+","+y2_top+" L "+x2+","+y2_bot+" C "+cx2+","+y2_bot+" "+cx1+","+y1_bot+" "+x1+","+y1_bot+" Z";
                                                                                }

                                                                                function updateSankey() {
                                                                                var d = calcPayroll(); if (d.max_val === 0) return;
                                                                                var scale = 350 / d.max_val, gap = 20, x0 = 0, x1 = 150, x2 = 300, x3 = 450, nw = 20;
                                                                                var emp_h = d.emp_cost * scale, brut_h = d.brut * scale, pat_h = d.pat * scale, net_h = d.net_imp * scale, sal_h = d.sal * scale, pay_h = d.net_pay * scale, tax_h = d.tax * scale;

                                                                                var p;
                                                                                if(p=getEl('path_emp_brut')) p.setAttribute('d', getSankeyPath(x0+nw, 25, 25+brut_h, x1, 25, 25+brut_h));
                                                                                if(p=getEl('path_emp_pat')) p.setAttribute('d', getSankeyPath(x0+nw, 25+brut_h, 25+emp_h, x1, 25+brut_h+gap, 25+brut_h+gap+pat_h));
                                                                                if(p=getEl('path_brut_net')) p.setAttribute('d', getSankeyPath(x1+nw, 25, 25+net_h, x2, 25, 25+net_h));
                                                                                if(p=getEl('path_brut_sal')) p.setAttribute('d', getSankeyPath(x1+nw, 25+net_h, 25+brut_h, x2, 25+net_h+gap, 25+net_h+gap+sal_h));
                                                                                if(p=getEl('path_net_pay')) p.setAttribute('d', getSankeyPath(x2+nw, 25, 25+pay_h, x3, 25, 25+pay_h));
                                                                                if(p=getEl('path_net_tax')) p.setAttribute('d', getSankeyPath(x2+nw, 25+pay_h, 25+net_h, x3, 25+pay_h+gap, 25+pay_h+gap+tax_h));

                                                                                var setRect = function(id, x, y, h) { var el = getEl(id); if(el) { el.setAttribute('x', x); el.setAttribute('y', y); el.setAttribute('width', nw); el.setAttribute('height', Math.max(1, h)); } };
                                                                                setRect('node_emp', x0, 25, emp_h); setRect('node_brut', x1, 25, brut_h); setRect('node_pat', x1, 25+brut_h+gap, pat_h); setRect('node_net', x2, 25, net_h); setRect('node_sal', x2, 25+net_h+gap, sal_h); setRect('node_pay', x3, 25, pay_h); setRect('node_tax', x3, 25+pay_h+gap, tax_h);

                                                                                var setText = function(id, x, y, txt) { var el = getEl(id); if(el) { el.setAttribute('x', x); el.setAttribute('y', y); el.textContent = txt; } };
                                                                                setText('text_emp', x0 - 10, 25 + emp_h/2, "Coût Employeur (" + Math.round(d.emp_cost) + " €)");
                                                                                setText('text_brut', x1 + nw + 10, 25 + brut_h/2, "Brut (" + Math.round(d.brut) + " €)");
                                                                                setText('text_pat', x1 + nw + 10, 25 + brut_h + gap + pat_h/2, "Cotis. Pat. (" + Math.round(d.pat) + " €)");
                                                                                setText('text_net', x2 + nw + 10, 25 + net_h/2, "Net Imposable (" + Math.round(d.net_imp) + " €)");
                                                                                setText('text_sal', x2 + nw + 10, 25 + net_h + gap + sal_h/2, "Cotis. Sal. (" + Math.round(d.sal) + " €)");
                                                                                setText('text_pay', x3 + nw + 10, 25 + pay_h/2, "Net à Payer (" + Math.round(d.net_pay) + " €)");
                                                                                setText('text_tax', x3 + nw + 10, 25 + pay_h + gap + tax_h/2, "PAS (" + Math.round(d.tax) + " €)");

                                                                                var statBoard = getEl('stat_board'); if (statBoard) {
                                                                                statBoard.innerHTML = ''; var tS=0, tP=0;
                                                                                var emp = DB.employes.find(function(e){return e.id === parseInt(getEl('pay_select_emp').value);});
                                                                                if(emp) {
                                                                                var profile = getActiveProfile(emp);
                                                                                if(profile) profile.rules.forEach(function(c){tS+=c.sal;tP+=c.pat;});
                                                                                }
                                                                                var cards = [{id:'brut',l:'Salaire Brut',v:Math.round(d.brut)+' €'},{id:'sal',l:'Taux Cotis. Sal.',v:tS.toFixed(2)+' %'},{id:'pat',l:'Taux Cotis. Pat.',v:tP.toFixed(2)+' %'},{id:'pas',l:'Taux PAS',v:d.pas_rate.toFixed(1)+' %'},{id:'net',l:'Net à Payer',v:Math.round(d.net_pay)+' €'},{id:'cout',l:'Coût Total',v:Math.round(d.emp_cost)+' €'}];
                                                                                for(var i=0; i<cards.length; i++) { var c=cards[i]; statBoard.innerHTML += '<div class="stat-card editable" id="card_'+c.id+'"><div class="stat-label">'+c.l+' [+]'+c.v+'</div></div>'; }
                                                                                    }
                                                                                    }

                                                                                    function updateSlidersFromDB() {
                                                                                    var empId = parseInt(getEl('pay_select_emp').value); var emp = DB.employes.find(function(e) { return e.id === empId; }); if (!emp) return;
                                                                                    var tS=0, tP=0;
                                                                                    var profile = getActiveProfile(emp);
                                                                                    if(profile) profile.rules.forEach(function(c){tS+=c.sal;tP+=c.pat;});
                                                                                    getEl('slider_brut').value = emp.salaire_base; getEl('val_slider_brut').textContent = emp.salaire_base + ' €';
                                                                                    getEl('slider_sal').value = tS.toFixed(2); getEl('val_slider_sal').textContent = tS.toFixed(2) + ' %';
                                                                                    getEl('slider_pat').value = tP.toFixed(2); getEl('val_slider_pat').textContent = tP.toFixed(2) + ' %';
                                                                                    getEl('slider_pas').value = emp.pas_rate || 0; getEl('val_slider_pas').textContent = (emp.pas_rate || 0) + ' %';
                                                                                    }

                                                                                    function renderHistory() {
                                                                                    var tbody = getEl('hist_table_body'); if (!tbody) return; tbody.innerHTML = ''; var rev = DB.bulletins.slice().reverse();
                                                                                    for (var i = 0; i < rev.length; i++) {
                                                                                        var b = rev[i]; var tr = E('tr');
                                                                                        tr.innerHTML = '<td>'+b.id+'</td><td>'+b.emp_name+'</td><td>'+b.mois+'/'+b.annee+'</td><td>'+Math.round(b.brut)+' €</td><td>'+Math.round(b.net)+' €</td><td>'+Math.round(b.cout)+' €</td><td style="white-space:nowrap;"><button class="btn btn-sm btn-info" id="view_bull_'+b.id+'" style="margin-right:5px;">Voir</button><button class="btn btn-sm btn-danger" id="del_bull_'+b.id+'">Suppr.</button></td>';
                                                                                        tbody.appendChild(tr);
                                                                                        }
                                                                                        }

                                                                                        function renderDashboard() {
                                                                                        var cY = parseInt(getEl('global_year').value) || new Date().getFullYear();
                                                                                        var mArr = []; for(var k=0; k<12; k++) mArr.push({brut:0,net:0,cost:0});
                                                                                            var data = { kpi:{brut:0,net:0,pat:0,cost:0}, months:mArr, quarters:[0,0,0,0], employees:{}, parity:{M:{c:0,s:0},F:{c:0,s:0}} };
                                                                                            for(var i=0; i<DB.employes.length; i++) { var em=DB.employes[i]; if(em.sexe==='F'){data.parity.F.c++;data.parity.F.s+=em.salaire_base;} else {data.parity.M.c++;data.parity.M.s+=em.salaire_base;} }
                                                                                                for (var i=0; i<DB.bulletins.length; i++) {
                                                                                                    var b = DB.bulletins[i]; if (parseInt(b.annee) === cY) {
                                                                                                    data.kpi.brut += b.brut; data.kpi.net += b.net; data.kpi.pat += b.pat; data.kpi.cost += b.cout;
                                                                                                    var m = parseInt(b.mois) - 1; if (m >= 0 && m < 12) { data.months[m].brut += b.brut; data.months[m].net += b.net; data.months[m].cost += b.cout; }
                                                                                                        var q = Math.floor((parseInt(b.mois)-1)/3); if(q>=0&&q<4) data.quarters[q] += b.cout;
                                                                                                            if (!data.employees[b.emp_name]) data.employees[b.emp_name] = 0; data.employees[b.emp_name] += b.cout;
                                                                                                            }
                                                                                                            }
                                                                                                            getEl('dash_kpi_brut').textContent = Math.round(data.kpi.brut) + ' €'; getEl('dash_kpi_net').textContent = Math.round(data.kpi.net) + ' €';
                                                                                                            getEl('dash_kpi_pat').textContent = Math.round(data.kpi.pat) + ' €'; getEl('dash_kpi_cost').textContent = Math.round(data.kpi.cost) + ' €';
                                                                                                            var mL = ['Jan','Fév','Mar','Avr','Mai','Juin','Juil','Aoû','Sep','Oct','Nov','Déc']; var cC = getEl('dash_monthly_chart'); cC.innerHTML = '';
                                                                                                            var mV = 1; for(var i=0; i<12; i++) if(data.months[i].cost>mV) mV=data.months[i].cost;
                                                                                                                for(var i=0; i<12; i++) { cC.innerHTML += '<div class="chart-bar-group"><div class="chart-bars"><div class="chart-bar brut" style="height:'+((data.months[i].brut/mV)*100)+'%;"></div><div class="chart-bar net" style="height:'+((data.months[i].net/mV)*100)+'%;"></div><div class="chart-bar cost" style="height:'+((data.months[i].cost/mV)*100)+'%;"></div></div><div class="chart-label">'+mL[i]+'</div></div>'; }
                                                                                                                    var dC = getEl('dash_quarterly_chart'); var tQ = data.quarters[0]+data.quarters[1]+data.quarters[2]+data.quarters[3] || 1; var dH='<div style="position:relative;width:180px;height:180px;"><svg viewBox="0 0 36 36" style="width:100%;height:100%;transform:rotate(-90deg);">'; var off=0; var cols=['#f59e0b','#4299e1','#48bb78','#ef4444'];
                                                                                                                            for(var i=0;i<4;i++){var pct=data.quarters[i]/tQ; var dash=pct*100; dH+='<circle cx="18" cy="18" r="15.915" fill="none" stroke="'+cols[i]+'" stroke-width="4" stroke-dasharray="'+dash+' '+(100-dash)+'" stroke-dashoffset="'+(-off)+'"></circle>'; off+=dash;} dH+='</svg><div style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);text-align:center;"><div style="font-size:12px;color:var(--text-muted);">TOTAL</div><div style="font-weight:bold;color:#fff;">'+Math.round(tQ)+' €</div></div></div><div>';
                                                                                                                            var qL=['T1','T2','T3','T4']; for(var i=0;i<4;i++) dH+='<div style="display:flex;align-items:center;gap:8px;"><div style="width:12px;height:12px;background:'+cols[i]+';border-radius:2px;"></div><span>'+qL[i]+'</span><span style="margin-left:auto;font-weight:bold;">'+Math.round(data.quarters[i])+' €</span></div>'; dH+='</div>'; dC.innerHTML=dH;
                                                                                                                            var tE = getEl('dash_top_emp'); var eA = Object.keys(data.employees).map(function(k){return {n:k,c:data.employees[k]};}); eA.sort(function(a,b){return b.c-a.c;}); var t5=eA.slice(0,5); var mE=1; if(t5.length>0)mE=t5[0].c; var eH='';
                                                                                                                            if(t5.length===0) eH='Aucune donnée'; else for(var i=0;i<t5.length;i++) eH+='<div class="top-emp-row"><div class="top-emp-name">'+t5[i].n+'</div><div class="top-emp-bar-bg"><div class="top-emp-bar-fill" style="width:'+((t5[i].c/mE)*100)+'%;"></div></div><div class="top-emp-val">'+Math.round(t5[i].c)+' €</div></div>'; tE.innerHTML=eH;
                                                                                                                                var pC = getEl('dash_parity_chart'); var aM=data.parity.M.c>0?data.parity.M.s/data.parity.M.c:0; var aF=data.parity.F.c>0?data.parity.F.s/data.parity.F.c:0; var mA=Math.max(aM,aF,1);
                                                                                                                                pC.innerHTML = '<div class="parity-col"><div class="parity-bar male" style="height:'+((aM/mA)*150)+'px;">'+Math.round(aM)+'€</div><div class="parity-label">H ('+data.parity.M.c+')</div></div><div class="parity-col"><div class="parity-bar female" style="height:'+((aF/mA)*150)+'px;">'+Math.round(aF)+'€</div><div class="parity-label">F ('+data.parity.F.c+')</div></div>';
                                                                                                                                var g = aM>0?((aM-aF)/aM)*100:0; if(aF>aM) g=-((aF-aM)/aF)*100;
                                                                                                                                getEl('dash_parity_gap').innerHTML = '<strong style="color:'+(Math.abs(g)>5?'var(--danger)':'var(--success)')+';">Écart : '+(g>0?'+':'')+g.toFixed(1)+'%</strong>';
                                                                                                                                }

                                                                                                                                function getBulletinHTML(b) {
                                                                                                                                if (b.sal === undefined) b.sal = 0; if (b.pat === undefined) b.pat = 0; if (b.net_social === undefined) b.net_social = b.net_imp || 0; if (b.net_imp === undefined) b.net_imp = b.net_social || 0; if (b.tax === undefined) b.tax = 0; if (!b.cotis_details) b.cotis_details = []; if (!b.line_items) b.line_items = []; if (b.reduc_fillon === undefined) b.reduc_fillon = 0; if (b.reduc_rqth === undefined) b.reduc_rqth = 0;
