                                                                                                                                    '.payslip-classique .ps-section-title{display:block;background:#e2e8f0;color:#000;padding:4px 8px;font-weight:bold;border-left:4px solid #000;margin-bottom:8px;text-transform:uppercase;font-size:12px}'+
                                                                                                                                    '.payslip-classique .ps-table{width:100%;border-collapse:collapse;margin-bottom:15px}'+
                                                                                                                                    '.payslip-classique .ps-table td{padding:4px;border-bottom:1px solid #ccc;font-size:12px}'+
                                                                                                                                    '.payslip-classique .ps-table td.t{text-align:right;font-weight:bold}'+
                                                                                                                                    '.payslip-classique .ps-total td{border-top:2px solid #000;font-weight:bold}'+
                                                                                                                                    '.payslip-classique .ps-net td{background:#f0fff4;color:#2c7a7b}'+
                                                                                                                                    '.payslip-classique .ps-cost td{background:#fff5f5;color:#c53030}'+
                                                                                                                                    '</style>';
                                                                                                                                } else if (template === 'moderne') {
                                                                                                                                css = '<style>'+
                                                                                                                                    '.payslip-moderne{font-family:"Arial",sans-serif;padding:0;color:#333;background:#fff;overflow:hidden;border-radius:12px}'+
                                                                                                                                    '.payslip-moderne h2{color:#fff;background:'+escapeXML(l.titlecolor)+';padding:20px;margin:0 0 20px 0;text-align:left;border-radius:0 0 12px 12px;font-size:22px;box-shadow:0 4px 6px rgba(0,0,0,0.1)}'+
                                                                                                                                    '.payslip-moderne .ps-header,.payslip-moderne .ps-info,.payslip-moderne .ps-grid{padding:0 20px}'+
                                                                                                                                    '.payslip-moderne .ps-header{display:flex;justify-content:space-between}'+
                                                                                                                                    '.payslip-moderne .ps-section-title{display:inline-block;color:'+escapeXML(l.titlecolor)+';font-weight:bold;font-size:12px;text-transform:uppercase;margin-bottom:10px;border-bottom:2px solid '+escapeXML(l.titlecolor)+';padding-bottom:2px}'+
                                                                                                                                    '.payslip-moderne .ps-table{width:100%;border-collapse:separate;border-spacing:0 4px;margin-bottom:15px}'+
                                                                                                                                    '.payslip-moderne .ps-table td{padding:8px 10px;background:#f8fafc;font-size:13px}'+
                                                                                                                                    '.payslip-moderne .ps-table td:first-child{border-radius:6px 0 0 6px}'+
                                                                                                                                    '.payslip-moderne .ps-table td.t{border-radius:0 6px 6px 0;font-weight:bold;background:#f1f5f9;text-align:right}'+
                                                                                                                                    '.payslip-moderne .ps-total td{background:#fff !important;border-top:2px solid #e2e8f0 !important;font-weight:bold}'+
                                                                                                                                    '.payslip-moderne .ps-total td:first-child{border-radius:0}'+
                                                                                                                                    '.payslip-moderne .ps-total td.t{border-radius:0}'+
                                                                                                                                    '.payslip-moderne .ps-net td{color:#fff !important;background:#2c7a7b !important;font-size:16px;border-radius:6px}'+
                                                                                                                                    '.payslip-moderne .ps-cost td{color:#fff !important;background:#c53030 !important;font-size:16px;border-radius:6px}'+
                                                                                                                                    '</style>';
                                                                                                                                } else if (template === 'minimaliste') {
                                                                                                                                css = '<style>'+
                                                                                                                                    '.payslip-minimaliste{font-family:"Helvetica Neue",Arial,sans-serif;padding:40px;color:#111;background:#fff}'+
                                                                                                                                    '.payslip-minimaliste h2{color:#111;background:none;border-bottom:1px solid #111;padding:0 0 20px 0;margin:0 0 30px 0;text-align:center;text-transform:uppercase;letter-spacing:4px;font-size:18px;font-weight:300}'+
                                                                                                                                    '.payslip-minimaliste .ps-header{border:none;padding:0;margin-bottom:20px}'+
                                                                                                                                    '.payslip-minimaliste .ps-section-title{display:block;color:#999;background:none;border-bottom:1px solid #eee;padding:0 0 5px 0;margin:20px 0 10px 0;text-transform:uppercase;font-size:11px;letter-spacing:1px}'+
                                                                                                                                    '.payslip-minimaliste .ps-table{width:100%;border-collapse:collapse;margin-bottom:10px}'+
                                                                                                                                    '.payslip-minimaliste .ps-table td{padding:6px 0;border:none;font-size:13px}'+
                                                                                                                                    '.payslip-minimaliste .ps-table td.t{text-align:right;font-weight:600}'+
                                                                                                                                    '.payslip-minimaliste .ps-total td{border-top:1px solid #111;padding:8px 0;font-weight:bold}'+
                                                                                                                                    '.payslip-minimaliste .ps-net td{font-size:18px;letter-spacing:1px}'+
                                                                                                                                    '.payslip-minimaliste .ps-cost td{font-size:18px;letter-spacing:1px}'+
                                                                                                                                    '</style>';
                                                                                                                                }

                                                                                                                                var c1='<div class="ps-section-title">Rémunération</div><table class="ps-table"><tr><td style="width:70%;">Salaire de Base</td><td class="t">'+(emp.salaire_base||0).toFixed(2)+' €</td></tr>';
                                                                                                                                    for(var i=0;i<b.line_items.length;i++){var it=b.line_items[i]; c1+='<tr><td>'+escapeXML(it.label)+'</td><td class="t">'+(it.type.indexOf('ded')!==-1?'-':'+')+it.amount.toFixed(2)+' €</td></tr>';}
                                                                                                                                        c1+='<tr class="ps-total"><td>SALAIRE BRUT</td><td class="t">'+b.brut.toFixed(2)+' €</td></tr></table>';

                                                                                                                                    var c2='<div class="ps-section-title">Cotisations Sociales</div><table class="ps-table">';
                                                                                                                                        var tS=0,tP=0;
                                                                                                                                        for(var i=0;i<b.cotis_details.length;i++){var c=b.cotis_details[i];tS+=c.partSal;tP+=c.partPat;c2+='<tr><td>'+escapeXML(c.nom)+'</td><td class="t">-'+c.partSal.toFixed(2)+' €</td></tr>';}
                                                                                                                                            c2+='<tr class="ps-total"><td>Total Sal.</td><td class="t">-'+tS.toFixed(2)+' €</td></tr></table>';

                                                                                                                                        var c3='<div class="ps-section-title">Synthèse &amp; Net</div><table class="ps-table"><tr class="ps-total"><td>NET SOCIAL</td><td class="t">'+b.net_social.toFixed(2)+' €</td></tr><tr><td>PAS ('+b.params_pas_rate+'%)</td><td class="t">-'+b.tax.toFixed(2)+' €</td></tr><tr class="ps-total ps-net"><td>NET A PAYER</td><td class="t">'+b.net.toFixed(2)+' €</td></tr></table><table class="ps-table"><tr class="ps-total"><td>Total Cot. Pat.</td><td class="t">'+tP.toFixed(2)+' €</td></tr><tr class="ps-total ps-cost"><td>COUT TOTAL</td><td class="t">'+b.cout.toFixed(2)+' €</td></tr></table>';

                                                                                                                                        var h='<div class="p payslip-'+template+'" style="page-break-after: always; margin-bottom: 50px;">'+css+'<h2>BULLETIN DE PAIE</h2><div class="ps-header" style="display:flex;justify-content:space-between;margin-bottom:20px;"><div class="ps-comp"><strong>'+escapeXML(DB.company.name)+'</strong><br/>'+escapeXML(DB.company.address)+'</div><div class="ps-emp" style="text-align:right;"><strong>'+escapeXML(emp.nom)+' '+escapeXML(emp.prenom)+'</strong><br/>'+escapeXML(emp.adresse)+(emp.rqth?'<br/><span style="color:#c53030;font-weight:bold;">Statut RQTH</span>':'')+'</div></div><div class="ps-info" style="border-top:1px dashed #999;padding-top:10px;margin-bottom:15px;display:flex;justify-content:space-between;flex-wrap:wrap;gap:10px;"><span><strong>Période:</strong> '+escapeXML(b.mois)+'/'+escapeXML(b.annee)+'</span><span><strong>Poste:</strong> '+escapeXML(emp.poste)+'</span></div><div class="ps-grid" style="display:grid;gap:20px;grid-template-columns:'+(cols===1?'1fr':(cols===2?'1fr 1fr':'1fr 1fr 1fr'))+';"><div>'+c1+'</div><div>'+c2+c3+'</div></div></div>';
                                                                                                                                        return h;
                                                                                                                                        }

                                                                                                                                        function showBulletin(id) { var b = DB.bulletins.find(function(x){return x.id===id;}); if(!b) return; getEl('bull_content').innerHTML = getBulletinHTML(b); getEl('modal_bull').style.display = 'flex'; }

                                                                                                                                        // ATTACH EVENTS
                                                                                                                                        getEl('btn_nav_dash').addEventListener('click', function(){ showView('dashboard'); });
                                                                                                                                        getEl('btn_nav_emp').addEventListener('click', function(){ showView('employes'); });
                                                                                                                                        getEl('btn_nav_pay').addEventListener('click', function(){ showView('paie'); });
                                                                                                                                        getEl('btn_nav_hist').addEventListener('click', function(){ showView('historique'); });
                                                                                                                                        getEl('btn_nav_param').addEventListener('click', function(){ showView('parametres'); });

                                                                                                                                        getEl('emp_table_body').addEventListener('click', function(e){ if(!e.target.id) return; if(e.target.id.indexOf('edit_emp_')===0) openEmpModal(parseInt(e.target.id.split('_')[2])); else if(e.target.id.indexOf('del_emp_')===0) { var id=parseInt(e.target.id.split('_')[2]); DB.employes=DB.employes.filter(function(em){return em.id!==id;}); saveDB(); renderEmployes(); populatePayrollDropdown(); } });
                                                                                                                                        getEl('btn_add_emp').addEventListener('click', function(){ openEmpModal(null); });
                                                                                                                                        getEl('btn_close_emp').addEventListener('click', function(){ getEl('modal_emp').style.display='none'; });
                                                                                                                                        getEl('btn_save_emp').addEventListener('click', function(){ var id=getEl('form_emp_id').value?parseInt(getEl('form_emp_id').value):null; var d={nom:getEl('form_emp_nom').value,prenom:getEl('form_emp_prenom').value,sexe:getEl('form_emp_sexe').value,poste:getEl('form_emp_poste').value,date_embauche:getEl('form_emp_date').value,contrat:getEl('form_emp_contrat').value,salaire_base:parseFloat(getEl('form_emp_salaire').value)||0,pas_rate:parseFloat(getEl('form_emp_pas').value)||0,rqth:getEl('form_emp_rqth').value==='true',rule_profile_id:parseInt(getEl('form_emp_profile').value),convention:getEl('form_emp_conv').value,adresse:getEl('form_emp_adresse').value,num_ss:getEl('form_emp_ss').value,rib:getEl('form_emp_iban').value}; if(id){var em=DB.employes.find(function(e){return e.id===id;}); if(em)Object.assign(em,d);} else {d.id=DB.nextEmpId++;DB.employes.push(d);} saveDB(); renderEmployes(); populatePayrollDropdown(); getEl('modal_emp').style.display='none'; showToast('Salarié enregistré'); });

                                                                                                                                        getEl('btn_add_pay_row').addEventListener('click', function(){ addPayRow('',0,'base','add_brut'); });
                                                                                                                                        getEl('pay_select_emp').addEventListener('change', function(){ updateSlidersFromDB(); updateSankey(); });
                                                                                                                                        getEl('btn_calc_pay').addEventListener('click', function(){
                                                                                                                                        var d=calcPayroll(); var id=parseInt(getEl('pay_select_emp').value); var em=DB.employes.find(function(e){return e.id===id;});
                                                                                                                                        var bull={
