                                                                                                                                        getEl('hist_table_body').addEventListener('click', function(e){ if(!e.target.id) return; var p=e.target.id.split('_'); if(p[0]+'_'+p[1]=='view_bull') showBulletin(parseInt(p[2])); else if(p[0]+'_'+p[1]=='del_bull') { DB.bulletins=DB.bulletins.filter(function(b){return b.id!==parseInt(p[2]);}); saveDB(); renderHistory(); updateSidebarStats(); } });
                                                                                                                                        getEl('btn_close_bull').addEventListener('click', function(){ getEl('modal_bull').style.display='none'; });
                                                                                                                                        getEl('btn_print_bull').addEventListener('click', function(){ var w=window.open('','_blank'); if(w){w.document.write('<html><body>'+getEl('bull_content').innerHTML+'</body></html>');w.document.close();w.print();} });
                                                                                                                                        getEl('btn_print_all').addEventListener('click', function(){ if(DB.bulletins.length===0){showToast('Aucun bulletin');return;} var h=''; for(var i=0;i<DB.bulletins.length;i++) h+=getBulletinHTML(DB.bulletins[i]); var w=window.open('','_blank'); if(w){w.document.write('<html><body>'+h+'</body></html>');w.document.close();w.print();} });

                                                                                                                                            getEl('btn_save_company').addEventListener('click', function(){ DB.company.name=getEl('company_name').value; DB.company.address=getEl('company_address').value; DB.company.siret=getEl('company_siret').value; DB.company.ape=getEl('company_ape').value; DB.company.conv=getEl('company_conv').value; DB.company.logo=getEl('company_logo').value; saveDB(); showToast('Entreprise sauvegardée'); });
                                                                                                                                            getEl('btn_save_layout').addEventListener('click', function(){ DB.params.layout.template=getEl('param_layout_template').value; DB.params.layout.font=getEl('param_layout_font').value; DB.params.layout.size=getEl('param_layout_size').value; DB.params.layout.margin=getEl('param_layout_margin').value; DB.params.layout.cols=getEl('param_layout_cols').value; DB.params.layout.titlecolor=getEl('param_layout_titlecolor').value; DB.params.layout.titlebg=getEl('param_layout_titlebg').value; DB.params.layout.header_note=getEl('param_layout_header_note').value; DB.params.layout.note=getEl('param_layout_note').value; saveDB(); showToast('Mise en page sauvegardée'); });

                                                                                                                                            // Rule Profiles Management
                                                                                                                                            getEl('rule_profile_select').addEventListener('change', function(e){ currentRuleProfileId = parseInt(e.target.value); loadParams(); });
                                                                                                                                            getEl('btn_add_profile').addEventListener('click', function(){
                                                                                                                                            var name = prompt("Entrez le nom du nouveau profil :", "Nouveau Profil");
                                                                                                                                            if(name) {
                                                                                                                                            DB.params.rule_profiles.push({ id: DB.params.nextProfileId++, name: name, smic: 1766.92, plafond_ss: 3864, rules: [] });
                                                                                                                                            currentRuleProfileId = DB.params.nextProfileId - 1; saveDB(); loadParams(); showToast('Profil créé');
                                                                                                                                            }
                                                                                                                                            });
                                                                                                                                            getEl('btn_dup_profile').addEventListener('click', function(){
                                                                                                                                            var profile = DB.params.rule_profiles.find(function(p){ return p.id == currentRuleProfileId; });
                                                                                                                                            if(!profile) return;
                                                                                                                                            var newName = prompt("Nom du nouveau profil (version) :", profile.name + " (Copie)");
                                                                                                                                            if(newName) {
                                                                                                                                            var deepCopyRules = JSON.parse(JSON.stringify(profile.rules));
                                                                                                                                            DB.params.rule_profiles.push({
                                                                                                                                            id: DB.params.nextProfileId++,
                                                                                                                                            name: newName,
                                                                                                                                            smic: profile.smic,
                                                                                                                                            plafond_ss: profile.plafond_ss,
                                                                                                                                            rules: deepCopyRules
                                                                                                                                            });
                                                                                                                                            currentRuleProfileId = DB.params.nextProfileId - 1;
                                                                                                                                            saveDB(); loadParams();
                                                                                                                                            showToast('Profil dupliqué');
                                                                                                                                            }
                                                                                                                                            });
                                                                                                                                            getEl('btn_del_profile').addEventListener('click', function(){
                                                                                                                                            if(DB.params.rule_profiles.length <= 1) { showToast('Impossible de supprimer le dernier profil'); return; }
                                                                                                                                                DB.params.rule_profiles = DB.params.rule_profiles.filter(function(p){ return p.id != currentRuleProfileId; });
                                                                                                                                                currentRuleProfileId = DB.params.rule_profiles[0].id; saveDB(); loadParams(); showToast('Profil supprimé');
                                                                                                                                                });

                                                                                                                                                getEl('btn_save_params').addEventListener('click', function(){
                                                                                                                                                DB.params.taux_fillon=parseFloat(getEl('param_taux_fillon').value)||0.3194; DB.params.aide_rqth=parseFloat(getEl('param_aide_rqth').value)||0;
                                                                                                                                                var r=[]; var rr=document.querySelectorAll('#ctrl_box .rule-row');
                                                                                                                                                for(var i=0;i<rr.length;i++) r.push({code:getEl('rule_code_'+i).value,nom:getEl('rule_nom_'+i).value,base:getEl('rule_base_'+i).value,sal:parseFloat(getEl('rule_sal_'+i).value)||0,pat:parseFloat(getEl('rule_pat_'+i).value)||0,plafond:parseInt(getEl('rule_plafond_'+i).value)||0});
                                                                                                                                                    var profile = DB.params.rule_profiles.find(function(p){ return p.id == currentRuleProfileId; });
                                                                                                                                                    if(profile) {
                                                                                                                                                    profile.rules = r;
                                                                                                                                                    profile.smic = parseFloat(getEl('param_smic').value) || 1766.92;
                                                                                                                                                    profile.plafond_ss = parseFloat(getEl('param_plafond').value) || 3864;
                                                                                                                                                    }
                                                                                                                                                    saveDB(); showToast('Règles sauvegardées');
                                                                                                                                                    });
                                                                                                                                                    getEl('btn_add_rule').addEventListener('click', function(){
                                                                                                                                                    var profile = DB.params.rule_profiles.find(function(p){ return p.id == currentRuleProfileId; });
                                                                                                                                                    if(profile) profile.rules.push({code:"NEW",nom:"Nouvelle",base:"brut",sal:0,pat:0,plafond:0}); saveDB(); loadParams();
                                                                                                                                                    });
                                                                                                                                                    getEl('ctrl_box').addEventListener('click', function(e){ if(e.target.id.indexOf('del_rule_')===0){
                                                                                                                                                    var profile = DB.params.rule_profiles.find(function(p){ return p.id == currentRuleProfileId; });
                                                                                                                                                    if(profile) profile.rules.splice(parseInt(e.target.id.split('_')[2]),1); saveDB(); loadParams();
                                                                                                                                                    } });

                                                                                                                                                    getEl('slider_brut').addEventListener('input', function(e){ var id=parseInt(getEl('pay_select_emp').value); var em=DB.employes.find(function(m){return m.id===id;}); if(em){em.salaire_base=parseFloat(e.target.value); getEl('val_slider_brut').textContent=em.salaire_base+' €'; saveDB(); updateSankey();} });
                                                                                                                                                    getEl('slider_sal').addEventListener('input', function(e){ var v=parseFloat(e.target.value); getEl('val_slider_sal').textContent=v.toFixed(2)+' %'; var c=0; var emp=DB.employes.find(function(m){return m.id===parseInt(getEl('pay_select_emp').value);}); if(emp){ var profile=getActiveProfile(emp); if(profile){ profile.rules.forEach(function(r){c+=r.sal;}); if(c>0){var f=v/c; profile.rules.forEach(function(r){r.sal=parseFloat((r.sal*f).toFixed(2));}); saveDB(); updateSankey();} } } });
                                                                                                                                                    getEl('slider_pat').addEventListener('input', function(e){ var v=parseFloat(e.target.value); getEl('val_slider_pat').textContent=v.toFixed(2)+' %'; var c=0; var emp=DB.employes.find(function(m){return m.id===parseInt(getEl('pay_select_emp').value);}); if(emp){ var profile=getActiveProfile(emp); if(profile){ profile.rules.forEach(function(r){c+=r.pat;}); if(c>0){var f=v/c; profile.rules.forEach(function(r){r.pat=parseFloat((r.pat*f).toFixed(2));}); saveDB(); updateSankey();} } } });
                                                                                                                                                    getEl('slider_pas').addEventListener('input', function(e){ var id=parseInt(getEl('pay_select_emp').value); var em=DB.employes.find(function(m){return m.id===id;}); if(em){em.pas_rate=parseFloat(e.target.value); getEl('val_slider_pas').textContent=em.pas_rate+' %'; saveDB(); updateSankey();} });

