                                                                                                                                                    getEl('btn_export').addEventListener('click', function(){ var c=document.documentElement.cloneNode(true); var s=c.getElementsByTagName('style')[0]; if(s) s.textContent='*{box-sizing:border-box}body{margin:0;background:#fff;color:#333;font-family:sans-serif}.panel{background:#f8f9fa;border:1px solid #ddd;padding:20px;margin:20px}h1,h2,h3{color:#333}.btn{display:none}input,select,textarea{width:100%;border:1px solid #ccc;padding:8px;margin-bottom:10px}.modal-overlay{display:none !important}#bg_rect{fill:#fff !important}'; var b=c.getElementById('bg_rect'); if(b) b.setAttribute('fill','#ffffff'); var sc=c.getElementsByTagName('script'); for(var i=sc.length-1;i>=0;i--) sc[i].parentNode.removeChild(sc[i]); var str=new XMLSerializer().serializeToString(c); if(str.indexOf('xmlns="http://www.w3.org/2000/svg"')===-1) str=str.replace('<svg','<svg xmlns="http://www.w3.org/2000/svg"'); getEl('export_text').value=str; getEl('modal_export').style.display='flex'; var l=getEl('download_link'); l.href=URL.createObjectURL(new Blob([str],{type:'image/svg+xml'})); });
                                                                                                                                                            getEl('btn_close_export').addEventListener('click', function(){ getEl('modal_export').style.display='none'; });

